import pandas as pd
import re

def execute_rule0(data):
    """
    Applies the rule: After grouping rows by a column [AgentID], the sum of a column ListPrice should be not greater than a predefined constant threshold 5000000.
    Explanation: Junior agents are capped at a total inventory value of 5 million.
    """

    def detect_number_format(column: pd.Series):
        sample_values = column.dropna().astype(str).sample(min(100, len(column)), random_state=42)
        decimal_like = 0
        thousands_like = 0
        mixed_usage = 0

        for value in sample_values:
            if '.' not in value and ',' not in value:
                continue
            if re.fullmatch(r"^\d{1,3}(?:\.\d{3})*(,\d{1,2})?$", value):
                thousands_like += 1
            elif re.fullmatch(r"^\d{1,3}(?:,\d{3})*(\.\d{1,2})?$", value):
                thousands_like += 1
            elif re.fullmatch(r"^\d+,\d{1,2}$", value):
                decimal_like += 1
            elif re.fullmatch(r"^\d+\.\d{1,2}$", value):
                decimal_like += 1
            else:
                mixed_usage += 1

        return {
            "decimal_like_count": decimal_like,
            "thousands_like_count": thousands_like,
            "mixed_usage_count": mixed_usage,
            "total_sampled": len(sample_values)
        }

    def convert_numeric_column(column: pd.Series):
        format_info = detect_number_format(column)
        if format_info["decimal_like_count"] + format_info["thousands_like_count"] > 0:
            if column.dtype == 'object':
                contains_comma_or_dot = column.str.contains(r'[,.]', regex=True, na=False)
                if format_info["decimal_like_count"] > format_info["thousands_like_count"]:
                    column.loc[contains_comma_or_dot] = column.loc[contains_comma_or_dot].str.replace(r'\.(?=\d{3})', '', regex=True)
                    column.loc[contains_comma_or_dot] = column.loc[contains_comma_or_dot].str.replace(',', '.', regex=True)
                else:
                    column.loc[contains_comma_or_dot] = column.loc[contains_comma_or_dot].str.replace(',', '', regex=True)
        return pd.to_numeric(column, errors='coerce') if column.dtype == 'object' else column

    # Rule-specific parameters
    group_by_columns = ["AgentID"]
    value_column = "ListPrice"
    threshold = 5000000

    # Convert ListPrice column to numeric
    data[value_column] = convert_numeric_column(data[value_column])
    data = data.reset_index()

    # Group by AgentID and calculate sum of ListPrice
    grouped = data.groupby(group_by_columns).agg(
        sum_value=(value_column, 'sum'),
        original_index_sum=('index', list)
    ).reset_index()

    satisfactions = {}
    violations = {}

    for row in grouped.itertuples(index=False):
        row_dict = row._asdict()
        group_key = tuple((col, row_dict[col]) for col in group_by_columns)
        entry = {
            "original_index_sum": row_dict["original_index_sum"]
        }
        if row_dict["sum_value"] <= threshold:
            satisfactions[group_key] = entry
        else:
            violations[group_key] = entry

    # Compute support and confidence
    unique_rows = set()
    for d in [satisfactions, violations]:
        for group in d.values():
            for val in group.values():
                if isinstance(val, list):
                    unique_rows.update(val)
                else:
                    unique_rows.add(val)

    support = len(unique_rows) / (len(data) + 1e-6)
    confidence = len(satisfactions) / (len(satisfactions) + len(violations) + 1e-6)

    return {
        "support": support,
        "confidence": confidence,
        "satisfactions": satisfactions,
        "violations": violations,
        "total_satisfactions": len(satisfactions),
        "total_violations": len(violations)
    }
